INSERT INTO "whatsapp_messages" ("id", "lead_id", "message_id", "body", "direction", "source", "tokens_used", "created_at", "updated_at") VALUES
	(1, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQzZBNUIzNzJERENCMERCOTExMDE2QUZERkUzQTg3OAA=', 'Que tipo de entrada tiene este cargador?  Para que tipos de celulares sirve ?', 'inbound', 'user', NULL, '2026-03-20 21:18:12', '2026-03-20 21:18:12'),
	(2, 1, NULL, 'Claro que sí, casero. El Cargador Inalámbrico MagSafe de Anker tiene una entrada USB-C para conectarlo a una fuente de alimentación. Sirve para celulares que sean compatibles con MagSafe, principalmente iPhones desde el modelo 12 en adelante, como iPhone 12, 13, 14, 15 y sus variantes Pro, así como otros dispositivos que soporten el estándar MagSafe. Es universal en ese sentido, asegurando una carga rápida y segura sin cables. ¿Te interesa comprarlo o necesitas más detalles?', 'outbound', 'ai', NULL, '2026-03-20 21:18:19', '2026-03-20 21:18:19'),
	(3, 1, NULL, 'buenas tardes, que modelo exactamente de celular tiene ?
', 'outbound', 'manual', NULL, '2026-03-20 21:19:55', '2026-03-20 21:19:55'),
	(4, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQzg4QzlCNkI2Q0I3NjA4MzQ2ODRDQzIwRkU3MDgwMQA=', 'Un pocox3 pro', 'inbound', 'user', NULL, '2026-03-20 21:20:27', '2026-03-20 21:20:27'),
	(5, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQ0IxQkZBQzg0QTJCOEU4MEY3OTdFODk0NjA0M0EzNwA=', 'Necesito más detalles', 'inbound', 'user', NULL, '2026-03-20 21:23:37', '2026-03-20 21:23:37'),
	(6, 1, NULL, 'Claro que sí, casero. Te doy más detalles sobre el Cargador Inalámbrico MagSafe de Anker: tiene una entrada USB-C, lo que significa que necesitas un cable USB-C para conectarlo a un adaptador de pared o puerto compatible. Sirve para celulares con tecnología MagSafe, principalmente iPhones desde el modelo 12 en adelante (como iPhone 12, 13, 14, 15 y sus versiones Pro, Plus, etc.), y también es compatible con otros dispositivos que soporten el estándar MagSafe, como algunos casos de AirPods o accesorios. Ofrece carga rápida inalámbrica con imanes para un acoplamiento seguro, disponible en colores blanco y transparente, y cuesta 220.00 Bs. Si buscas algo más básico, también tengo el Cargador Rápido 20W USB-C de Apple por 190.00 Bs, con entrada USB-C y compatible universalmente. ¿Te gustaría comprar alguno o necesitas más información específica?', 'outbound', 'ai', NULL, '2026-03-20 21:23:47', '2026-03-20 21:23:47'),
	(7, 5, 'wamid.HBgLNTkxNjgwNzQ3OTEVAgASGBQzQTk2MUQzQUNGQjZGNUUxNkUwNQA=', 'Hola quiero mas informacion', 'inbound', 'user', NULL, '2026-03-20 22:53:12', '2026-03-20 22:53:12'),
