	(9, 5, NULL, '¡Hola! Estamos experimentando alta demanda. ¿En qué te puedo ayudar hoy?', 'outbound', 'ai', 0, '2026-03-20 23:01:49', '2026-03-20 23:01:49'),
	(10, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQzU2NjIwMzgzMkY1MDNFQzZBRDBBMUE1M0E2QUVGNAA=', 'Hola quiero el catálogo', 'inbound', 'user', NULL, '2026-03-20 23:02:42', '2026-03-20 23:02:42'),
