	(33, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQzBDNDZDM0UzMDNGQzgzM0YzN0QzNUUxQUI1M0U1RQA=', 'Hola busco un cargador rápido', 'inbound', 'user', NULL, '2026-03-25 00:28:32', '2026-03-25 00:28:32'),
	(34, 1, NULL, '¡Hola! Qué bueno que preguntás por un cargador rápido. Acá tengo dos opciones que te van a encantar. Primero, el Cargador Rápido 20W USB-C de Apple, a 190 Bs, es transparente y universal, ideal para cargar rápido tu celu. También está el Cargador Inalámbrico MagSafe de Anker, a 220 Bs, viene en blanco o transparente, es universal y se pega con imán para más comodidad. ¿Cuál te interesa más para que te lo reserve?', 'outbound', 'ai', 424, '2026-03-25 00:28:45', '2026-03-25 00:28:45'),
	(35, 1, 'wamid.HBgLNTkxNzc1Mzc0MjMVAgASGCBBQ0Y2QzE2MjcxODI3MkIyQkFCMkE2RDBCRTlCNUU0QgA=', 'En qué color tienes el de Apple?', 'inbound', 'user', NULL, '2026-03-25 00:30:15', '2026-03-25 00:30:15'),
